                      "zh": "一部分",
                      "pinyin": "yí bùfen",
                      "vi": "Một phần",
                      "audio": "audio/catalog/dialogue/beginner/topic-work-with-chinese-boss-colleagues-001/words/daily-003-keyword-010.mp3"
