                  "sentences": [
                    {
                      "id": "daily-010-s001",
                      "order": 1,
                      "speaker": "A",
                      "zh": "阿南，今天感觉怎么样？",
                      "pinyin": "Ā Nán, jīntiān gǎnjué zěnmeyàng?",
                      "vi": "A Nam, hôm nay cảm thấy thế nào?",
                      "start": 0,
                      "end": 2.715
                    },
                    {
                      "id": "daily-010-s002",
                      "order": 2,
                      "speaker": "B",
                      "zh": "有点儿累，但是我学到了很多。",
                      "pinyin": "Yǒu diǎnr lèi, dànshì wǒ xué dào le hěn duō.",
                      "vi": "Hơi mệt, nhưng tôi học được rất nhiều.",
                      "start": 2.715,
                      "end": 5.936
                    },
                    {
                      "id": "daily-010-s003",
                      "order": 3,
                      "speaker": "A",
                      "zh": "你今天用中文做了不少事情。",
                      "pinyin": "Nǐ jīntiān yòng Zhōngwén zuò le bù shǎo shìqing.",
                      "vi": "Hôm nay bạn dùng tiếng Trung làm khá nhiều việc.",
                      "start": 5.936,
                      "end": 9.58
                    },
                    {
                      "id": "daily-010-s004",
                      "order": 4,
                      "speaker": "B",
                      "zh": "是啊。早上报到，上午看资料，下午开会。",
                      "pinyin": "Shì a. Zǎoshang bàodào, shàngwǔ kàn zīliào, xiàwǔ kāihuì.",
                      "vi": "Đúng vậy. Sáng nhận việc, buổi sáng xem tài liệu, chiều họp.",
                      "start": 9.58,
                      "end": 14.101
                    },
                    {
                      "id": "daily-010-s005",
                      "order": 5,
                      "speaker": "C",
                      "zh": "阿南，今天的客户名单整理得怎么样？",
                      "pinyin": "Ā Nán, jīntiān de kèhù míngdān zhěnglǐ de zěnmeyàng?",
                      "vi": "A Nam, danh sách khách hàng hôm nay sắp xếp thế nào rồi?",
                      "start": 14.101,
                      "end": 18.766
                    },
                    {
                      "id": "daily-010-s006",
                      "order": 6,
                      "speaker": "B",
                      "zh": "王经理，我已经整理完，也检查了一遍。",
                      "pinyin": "Wáng jīnglǐ, wǒ yǐjīng zhěnglǐ wán, yě jiǎnchá le yí biàn.",
                      "vi": "Quản lý Vương, tôi đã sắp xếp xong, cũng kiểm tra một lượt.",
                      "start": 18.766,
                      "end": 22.577
                    },
                    {
                      "id": "daily-010-s007",
                      "order": 7,
                      "speaker": "C",
                      "zh": "很好。有没有不确定的地方？",
                      "pinyin": "Hěn hǎo. Yǒu méiyǒu bù quèdìng de dìfang?",
                      "vi": "Rất tốt. Có chỗ nào chưa chắc không?",
                      "start": 22.577,
                      "end": 25.823
                    },
                    {
                      "id": "daily-010-s008",
                      "order": 8,
                      "speaker": "B",
                      "zh": "有三个电话不完整，我用红色标出来了。",
                      "pinyin": "Yǒu sān ge diànhuà bù wánzhěng, wǒ yòng hóngsè biāo chūlai le.",
                      "vi": "Có ba số điện thoại không đầy đủ, tôi đã đánh dấu màu đỏ.",
                      "start": 25.823,
                      "end": 29.76
                    },
                    {
                      "id": "daily-010-s009",
                      "order": 9,
                      "speaker": "C",
                      "zh": "处理得不错。等客服确认以后再改。",
                      "pinyin": "Chǔlǐ de bú cuò. Děng kèfú quèrèn yǐhòu zài gǎi.",
                      "vi": "Xử lý khá tốt. Đợi chăm sóc khách hàng xác nhận rồi sửa.",
                      "start": 29.76,
                      "end": 34.181
                    },
                    {
                      "id": "daily-010-s010",
                      "order": 10,
                      "speaker": "B",
                      "zh": "好的。我今天还学会了怎么写备注。",
                      "pinyin": "Hǎo de. Wǒ jīntiān hái xuéhuì le zěnme xiě bèizhù.",
                      "vi": "Được. Hôm nay tôi còn học được cách viết ghi chú.",
                      "start": 34.181,
                      "end": 38.004
                    },
                    {
                      "id": "daily-010-s011",
                      "order": 11,
                      "speaker": "A",
                      "zh": "他今天进步很快，也敢开口问问题。",
                      "pinyin": "Tā jīntiān jìnbù hěn kuài, yě gǎn kāikǒu wèn wèntí.",
                      "vi": "Hôm nay anh ấy tiến bộ rất nhanh, cũng dám mở miệng hỏi vấn đề.",
                      "start": 38.004,
                      "end": 42.229
                    },
                    {
                      "id": "daily-010-s012",
                      "order": 12,
                      "speaker": "C",
                      "zh": "很好。新员工最重要的是主动问、认真做。",
                      "pinyin": "Hěn hǎo. Xīn yuángōng zuì zhòngyào de shì zhǔdòng wèn, rènzhēn zuò.",
                      "vi": "Rất tốt. Nhân viên mới quan trọng nhất là chủ động hỏi và làm nghiêm túc.",
                      "start": 42.229,
                      "end": 47.539
                    },
                    {
                      "id": "daily-010-s013",
                      "order": 13,
                      "speaker": "B",
                      "zh": "谢谢。今天我一开始很紧张，现在好多了。",
                      "pinyin": "Xièxie. Jīntiān wǒ yì kāishǐ hěn jǐnzhāng, xiànzài hǎo duō le.",
                      "vi": "Cảm ơn. Hôm nay lúc đầu tôi rất căng thẳng, bây giờ đỡ hơn nhiều rồi.",
                      "start": 47.539,
                      "end": 51.905
                    },
                    {
                      "id": "daily-010-s014",
                      "order": 14,
                      "speaker": "C",
                      "zh": "明天你继续整理客户资料，下午学习系统操作。",
                      "pinyin": "Míngtiān nǐ jìxù zhěnglǐ kèhù zīliào, xiàwǔ xuéxí xìtǒng cāozuò.",
                      "vi": "Ngày mai bạn tiếp tục sắp xếp tài liệu khách hàng, buổi chiều học thao tác hệ thống.",
                      "start": 51.905,
                      "end": 57.371
                    },
                    {
                      "id": "daily-010-s015",
                      "order": 15,
                      "speaker": "B",
                      "zh": "好的。明天我需要几点到公司？",
                      "pinyin": "Hǎo de. Míngtiān wǒ xūyào jǐ diǎn dào gōngsī?",
                      "vi": "Được. Ngày mai tôi cần mấy giờ đến công ty?",
                      "start": 57.371,
                      "end": 60.471
                    },
                    {
                      "id": "daily-010-s016",
                      "order": 16,
                      "speaker": "C",
                      "zh": "九点前到就可以。不要迟到。",
                      "pinyin": "Jiǔ diǎn qián dào jiù kě yǐ. Bú yào chídào.",
                      "vi": "Đến trước 9 giờ là được. Đừng đến muộn.",
                      "start": 60.471,
                      "end": 64.365
                    },
                    {
                      "id": "daily-010-s017",
                      "order": 17,
                      "speaker": "B",
                      "zh": "明白。我会提前十分钟到。",
                      "pinyin": "Míngbai. Wǒ huì tíqián shí fēnzhōng dào.",
                      "vi": "Tôi hiểu. Tôi sẽ đến sớm 10 phút.",
                      "start": 64.365,
                      "end": 67.323
                    },
                    {
                      "id": "daily-010-s018",
                      "order": 18,
                      "speaker": "A",
                      "zh": "下班以后你要不要一起走？",
                      "pinyin": "Xiàbān yǐhòu nǐ yào bu yào yìqǐ zǒu?",
                      "vi": "Sau giờ làm bạn có muốn đi về cùng không?",
                      "start": 67.323,
                      "end": 69.481
                    },
                    {
                      "id": "daily-010-s019",
                      "order": 19,
                      "speaker": "B",
                      "zh": "好啊。今天谢谢你们帮我。",
                      "pinyin": "Hǎo a. Jīntiān xièxie nǐmen bāng wǒ.",
                      "vi": "Được chứ. Hôm nay cảm ơn mọi người đã giúp tôi.",
                      "start": 69.481,
                      "end": 72.335
                    },
                    {
                      "id": "daily-010-s020",
                      "order": 20,
                      "speaker": "C",
                      "zh": "不用客气。明天继续加油。",
                      "pinyin": "Bú yòng kèqi. Míngtiān jìxù jiāyóu.",
                      "vi": "Không cần khách sáo. Ngày mai tiếp tục cố gắng.",
                      "start": 72.335,
                      "end": 75.983
                    }
                  ],
