                  "title_zh": "客户问什么时候发货",
                  "title_vi": "Khách hỏi khi nào gửi hàng",
                  "main_audio_includes_title": false,
                  "title_audio": "audio/catalog/dialogue/beginner/topic-chat-with-chinese-customers-001/title/daily-004-title.mp3",
                  "main_audio": "audio/catalog/dialogue/beginner/topic-chat-with-chinese-customers-001/main/daily-004-main.mp3",
                  "speaker": "A/B",
                  "roles": [
                    {
                      "speaker": "A",
                      "name_zh": "客户",
                      "name_vi": "Khách hàng",
                      "gender": "male",
                      "role_zh": "客户",
                      "role_vi": "khách hàng",
                      "voice_name": "明远",
                      "voice_id": "2847124c",
                      "voice_key": "dialogue_male_secondary",
                      "speaker_key": "dialogue_male_secondary"
                    },
                    {
                      "speaker": "B",
                      "name_zh": "阿南",
                      "name_vi": "A Nam",
                      "gender": "male",
                      "role_zh": "新员工",
                      "role_vi": "nhân viên mới",
                      "voice_name": "俊杰",
                      "voice_id": "3e2a5eff",
                      "voice_key": "dialogue_male_daily",
                      "speaker_key": "dialogue_male_daily"
                    }
                  ],
                  "sentences": [
                    {
                      "id": "daily-004-s001",
                      "order": 1,
                      "speaker": "A",
                      "zh": "你好，我已经付款了。",
                      "pinyin": "Nǐ hǎo, wǒ yǐjīng fùkuǎn le.",
                      "vi": "Xin chào, tôi đã thanh toán rồi.",
                      "start": 0,
                      "end": 2.782
                    },
                    {
                      "id": "daily-004-s002",
                      "order": 2,
                      "speaker": "B",
                      "zh": "好的，我看到了。谢谢你。",
                      "pinyin": "Hǎo de, wǒ kàn dào le. Xièxie nǐ.",
                      "vi": "Được, tôi đã thấy rồi. Cảm ơn bạn.",
                      "start": 2.782,
                      "end": 5.822
                    },
                    {
                      "id": "daily-004-s003",
                      "order": 3,
                      "speaker": "A",
                      "zh": "请问什么时候发货？",
                      "pinyin": "Qǐngwèn shénme shíhou fā huò?",
                      "vi": "Cho hỏi khi nào gửi hàng?",
                      "start": 5.822,
                      "end": 8.76
                    },
                    {
                      "id": "daily-004-s004",
                      "order": 4,
                      "speaker": "B",
                      "zh": "今天下午五点前可以发货。",
                      "pinyin": "Jīntiān xiàwǔ wǔ diǎn qián kě yǐ fā huò.",
                      "vi": "Trước 5 giờ chiều nay có thể gửi hàng.",
                      "start": 8.76,
                      "end": 11.695
                    },
                    {
                      "id": "daily-004-s005",
                      "order": 5,
                      "speaker": "A",
                      "zh": "大概几天能到？",
                      "pinyin": "Dàgài jǐ tiān néng dào?",
                      "vi": "Khoảng mấy ngày thì đến?",
                      "start": 11.695,
                      "end": 14.129
                    },
                    {
                      "id": "daily-004-s006",
                      "order": 6,
                      "speaker": "B",
                      "zh": "一般三到五天可以到。",
                      "pinyin": "Yìbān sān dào wǔ tiān kě yǐ dào.",
                      "vi": "Thông thường 3 đến 5 ngày có thể đến.",
                      "start": 14.129,
                      "end": 16.382
                    },
                    {
                      "id": "daily-004-s007",
                      "order": 7,
                      "speaker": "A",
                      "zh": "可以发快递单号给我吗？",
                      "pinyin": "Kě yǐ fā kuàidì dānhào gěi wǒ ma?",
                      "vi": "Có thể gửi mã vận đơn cho tôi không?",
                      "start": 16.382,
                      "end": 19.384
                    },
                    {
                      "id": "daily-004-s008",
                      "order": 8,
                      "speaker": "B",
                      "zh": "可以。发货以后，我马上发给你。",
                      "pinyin": "Kě yǐ. Fā huò yǐhòu, wǒ mǎshàng fā gěi nǐ.",
                      "vi": "Được. Sau khi gửi hàng, tôi sẽ gửi cho bạn ngay.",
                      "start": 19.384,
                      "end": 22.501
                    },
                    {
                      "id": "daily-004-s009",
                      "order": 9,
                      "speaker": "A",
                      "zh": "好的，我需要注意什么吗？",
                      "pinyin": "Hǎo de, wǒ xūyào zhùyì shénme ma?",
                      "vi": "Được, tôi cần chú ý gì không?",
                      "start": 22.501,
                      "end": 25.801
                    },
                    {
                      "id": "daily-004-s010",
                      "order": 10,
                      "speaker": "B",
                      "zh": "请保持手机可以联系。快递员可能会给你打电话。",
                      "pinyin": "Qǐng bǎochí shǒujī kě yǐ liánxì. Kuàidìyuán kěnéng huì gěi nǐ dǎ diànhuà.",
                      "vi": "Vui lòng giữ điện thoại liên lạc được. Nhân viên giao hàng có thể gọi cho bạn.",
                      "start": 25.801,
                      "end": 31.106
                    },
                    {
                      "id": "daily-004-s011",
                      "order": 11,
                      "speaker": "A",
                      "zh": "明白了。",
                      "pinyin": "Míngbai le.",
                      "vi": "Tôi hiểu rồi.",
                      "start": 31.106,
                      "end": 32.404
                    },
                    {
                      "id": "daily-004-s012",
                      "order": 12,
                      "speaker": "B",
                      "zh": "如果有问题，你可以随时联系我。",
                      "pinyin": "Rúguǒ yǒu wèntí, nǐ kě yǐ suíshí liánxì wǒ.",
                      "vi": "Nếu có vấn đề, bạn có thể liên hệ tôi bất cứ lúc nào.",
                      "start": 32.404,
                      "end": 35.788
                    },
                    {
                      "id": "daily-004-s013",
                      "order": 13,
                      "speaker": "A",
                      "zh": "好，谢谢。",
                      "pinyin": "Hǎo, xièxie.",
                      "vi": "Được, cảm ơn.",
                      "start": 35.788,
                      "end": 37.551
                    },
                    {
                      "id": "daily-004-s014",
                      "order": 14,
                      "speaker": "B",
                      "zh": "不客气。",
                      "pinyin": "Bú kèqi.",
                      "vi": "Không có gì.",
                      "start": 37.551,
                      "end": 38.998
                    }
                  ],
