                  "sentences": [
                    {
                      "id": "daily-006-s001",
                      "order": 1,
                      "speaker": "A",
                      "zh": "你好，可以给我发一下产品图片吗？",
                      "pinyin": "Nǐ hǎo, kě yǐ gěi wǒ fā yí xià chǎnpǐn túpiàn ma?",
                      "vi": "Xin chào, có thể gửi cho tôi ảnh sản phẩm không?",
                      "start": 0,
                      "end": 4.408
                    },
                    {
                      "id": "daily-006-s002",
                      "order": 2,
                      "speaker": "B",
                      "zh": "可以，我马上发给你。",
                      "pinyin": "Kě yǐ, wǒ mǎshàng fā gěi nǐ.",
                      "vi": "Được, tôi gửi cho bạn ngay.",
                      "start": 4.408,
                      "end": 7.102
                    },
                    {
                      "id": "daily-006-s003",
                      "order": 3,
                      "speaker": "A",
                      "zh": "还有尺寸信息吗？",
                      "pinyin": "Hái yǒu chǐcùn xìnxī ma?",
                      "vi": "Còn có thông tin kích thước không?",
                      "start": 7.102,
                      "end": 9.64
                    },
                    {
                      "id": "daily-006-s004",
                      "order": 4,
                      "speaker": "B",
                      "zh": "有的。我把尺寸表也发给你。",
                      "pinyin": "Yǒu de. Wǒ bǎ chǐcùn biǎo yě fā gěi nǐ.",
                      "vi": "Có. Tôi cũng gửi bảng kích thước cho bạn.",
                      "start": 9.64,
                      "end": 12.61
                    },
                    {
                      "id": "daily-006-s005",
                      "order": 5,
                      "speaker": "A",
                      "zh": "这个产品重吗？",
                      "pinyin": "Zhè ge chǎnpǐn zhòng ma?",
                      "vi": "Sản phẩm này có nặng không?",
                      "start": 12.61,
                      "end": 14.967
                    },
                    {
                      "id": "daily-006-s006",
                      "order": 6,
                      "speaker": "B",
                      "zh": "不重，大概三百克。",
                      "pinyin": "Bù zhòng, dàgài sān bǎi kè.",
                      "vi": "Không nặng, khoảng 300 gram.",
                      "start": 14.967,
                      "end": 17.673
                    },
                    {
                      "id": "daily-006-s007",
                      "order": 7,
                      "speaker": "A",
                      "zh": "材质是什么？",
                      "pinyin": "Cáizhì shì shénme?",
                      "vi": "Chất liệu là gì?",
                      "start": 17.673,
                      "end": 19.9
                    },
                    {
                      "id": "daily-006-s008",
                      "order": 8,
                      "speaker": "B",
                      "zh": "主要是塑料和金属。",
                      "pinyin": "Zhǔyào shì sùliào hé jīnshǔ.",
                      "vi": "Chủ yếu là nhựa và kim loại.",
                      "start": 19.9,
                      "end": 22.861
                    },
                    {
                      "id": "daily-006-s009",
                      "order": 9,
                      "speaker": "A",
                      "zh": "有使用说明吗？",
                      "pinyin": "Yǒu shǐyòng shuōmíng ma?",
                      "vi": "Có hướng dẫn sử dụng không?",
                      "start": 22.861,
                      "end": 25.063
                    },
                    {
                      "id": "daily-006-s010",
                      "order": 10,
                      "speaker": "B",
                      "zh": "有。我可以发中文说明给你。",
                      "pinyin": "Yǒu. Wǒ kě yǐ fā Zhōngwén shuōmíng gěi nǐ.",
                      "vi": "Có. Tôi có thể gửi hướng dẫn tiếng Trung cho bạn.",
                      "start": 25.063,
                      "end": 28.409
                    },
                    {
                      "id": "daily-006-s011",
                      "order": 11,
                      "speaker": "A",
                      "zh": "好的，请发给我。",
                      "pinyin": "Hǎo de, qǐng fā gěi wǒ.",
                      "vi": "Được, vui lòng gửi cho tôi.",
                      "start": 28.409,
                      "end": 31.012
                    },
                    {
                      "id": "daily-006-s012",
                      "order": 12,
                      "speaker": "B",
                      "zh": "已经发了，你看一下。",
                      "pinyin": "Yǐjīng fā le, nǐ kàn yí xià.",
                      "vi": "Tôi đã gửi rồi, bạn xem một chút.",
                      "start": 31.012,
                      "end": 33.681
                    },
                    {
                      "id": "daily-006-s013",
                      "order": 13,
                      "speaker": "A",
                      "zh": "收到了，谢谢。",
                      "pinyin": "Shōu dào le, xièxie.",
                      "vi": "Tôi nhận được rồi, cảm ơn.",
                      "start": 33.681,
                      "end": 36.115
                    },
                    {
                      "id": "daily-006-s014",
                      "order": 14,
                      "speaker": "B",
                      "zh": "不客气，有问题可以问我。",
                      "pinyin": "Bú kèqi, yǒu wèntí kě yǐ wèn wǒ.",
                      "vi": "Không có gì, có vấn đề bạn có thể hỏi tôi.",
                      "start": 36.115,
                      "end": 38.837
                    }
                  ],
