                      "order": 14,
                      "speaker": "B",
                      "zh": "好的，我等你的信息。",
                      "pinyin": "Hǎo de, wǒ děng nǐ de xìnxī.",
                      "vi": "Được, tôi đợi thông tin của bạn.",
                      "start": 41.304,
