                  "sentences": [
                    {
                      "id": "daily-006-s001",
                      "order": 1,
                      "speaker": "A",
                      "zh": "小玲，你怎么了？脸色不太好。",
                      "pinyin": "Xiǎo Líng, nǐ zěnme le? Liǎnsè bú tài hǎo.",
                      "vi": "Tiểu Linh, bạn sao vậy? Sắc mặt không tốt lắm.",
                      "start": 0,
                      "end": 3.609
                    },
                    {
                      "id": "daily-006-s002",
                      "order": 2,
                      "speaker": "B",
                      "zh": "我肚子有点儿疼。",
                      "pinyin": "Wǒ dùzi yǒu diǎnr téng.",
                      "vi": "Tôi hơi đau bụng.",
                      "start": 3.609,
                      "end": 6.366
                    },
                    {
                      "id": "daily-006-s003",
                      "order": 3,
                      "speaker": "A",
                      "zh": "是不是吃坏东西了？",
                      "pinyin": "Shì bú shì chī huài dōngxi le?",
                      "vi": "Có phải ăn đồ hỏng rồi không?",
                      "start": 6.366,
                      "end": 9.054
                    },
                    {
                      "id": "daily-006-s004",
                      "order": 4,
                      "speaker": "B",
                      "zh": "可能是。中午我吃了很辣的菜。",
                      "pinyin": "Kěnéng shì. Zhōngwǔ wǒ chī le hěn là de cài.",
                      "vi": "Có thể. Buổi trưa tôi ăn món rất cay.",
                      "start": 9.054,
                      "end": 12.043
                    },
                    {
                      "id": "daily-006-s005",
                      "order": 5,
                      "speaker": "A",
                      "zh": "你平时能吃辣吗？",
                      "pinyin": "Nǐ píngshí néng chī là ma?",
                      "vi": "Bình thường bạn ăn cay được không?",
                      "start": 12.043,
                      "end": 14.531
                    },
                    {
                      "id": "daily-006-s006",
                      "order": 6,
                      "speaker": "B",
                      "zh": "不太能。今天吃得有点儿多。",
                      "pinyin": "Bú tài néng. Jīntiān chī de yǒu diǎnr duō.",
                      "vi": "Không ăn được lắm. Hôm nay ăn hơi nhiều.",
                      "start": 14.531,
                      "end": 17.803
                    },
                    {
                      "id": "daily-006-s007",
                      "order": 7,
                      "speaker": "A",
                      "zh": "你要不要喝点热水？",
                      "pinyin": "Nǐ yào bu yào hē diǎn rè shuǐ?",
                      "vi": "Bạn có muốn uống chút nước nóng không?",
                      "start": 17.803,
                      "end": 20.076
                    },
                    {
                      "id": "daily-006-s008",
                      "order": 8,
                      "speaker": "B",
                      "zh": "好，谢谢。",
                      "pinyin": "Hǎo, xièxie.",
                      "vi": "Được, cảm ơn.",
                      "start": 20.076,
                      "end": 21.802
                    },
                    {
                      "id": "daily-006-s009",
                      "order": 9,
                      "speaker": "A",
                      "zh": "如果还是疼，你最好去医院看看。",
                      "pinyin": "Rúguǒ háishi téng, nǐ zuì hǎo qù yīyuàn kànkan.",
                      "vi": "Nếu vẫn đau, tốt nhất bạn đi bệnh viện khám xem.",
                      "start": 21.802,
                      "end": 25.294
                    },
                    {
                      "id": "daily-006-s010",
                      "order": 10,
                      "speaker": "B",
                      "zh": "我先休息一下。如果不好，我就去医院。",
                      "pinyin": "Wǒ xiān xiūxi yí xià. Rúguǒ bù hǎo, wǒ jiù qù yīyuàn.",
                      "vi": "Tôi nghỉ một chút trước. Nếu không ổn, tôi sẽ đi bệnh viện.",
                      "start": 25.294,
                      "end": 28.594
                    },
                    {
                      "id": "daily-006-s011",
                      "order": 11,
                      "speaker": "A",
                      "zh": "你要不要跟经理请假？",
                      "pinyin": "Nǐ yào bu yào gēn jīnglǐ qǐngjià?",
                      "vi": "Bạn có muốn xin nghỉ với quản lý không?",
                      "start": 28.594,
                      "end": 30.845
                    },
                    {
                      "id": "daily-006-s012",
                      "order": 12,
                      "speaker": "B",
                      "zh": "可能需要。我怕下午不能工作。",
                      "pinyin": "Kěnéng xūyào. Wǒ pà xiàwǔ bù néng gōngzuò.",
                      "vi": "Có thể cần. Tôi sợ chiều không làm việc được.",
                      "start": 30.845,
                      "end": 33.718
                    },
                    {
                      "id": "daily-006-s013",
                      "order": 13,
                      "speaker": "A",
                      "zh": "我可以帮你跟经理说。",
                      "pinyin": "Wǒ kě yǐ bāng nǐ gēn jīnglǐ shuō.",
                      "vi": "Tôi có thể giúp bạn nói với quản lý.",
                      "start": 33.718,
                      "end": 36.094
                    },
                    {
                      "id": "daily-006-s014",
                      "order": 14,
                      "speaker": "B",
                      "zh": "太谢谢你了。",
                      "pinyin": "Tài xièxie nǐ le.",
                      "vi": "Cảm ơn bạn nhiều quá.",
                      "start": 36.094,
                      "end": 38.609
                    }
                  ],
