                  "sentences": [
                    {
                      "id": "daily-009-s001",
                      "order": 1,
                      "speaker": "A",
                      "zh": "喂，你好。",
                      "pinyin": "Wèi, nǐ hǎo.",
                      "vi": "Alo, xin chào.",
                      "start": 0,
                      "end": 1.983
                    },
                    {
                      "id": "daily-009-s002",
                      "order": 2,
                      "speaker": "B",
                      "zh": "你好，请问是李经理吗？",
                      "pinyin": "Nǐ hǎo, qǐngwèn shì Lǐ jīnglǐ ma?",
                      "vi": "Xin chào, cho hỏi có phải quản lý Lý không?",
                      "start": 1.983,
                      "end": 4.862
                    },
                    {
                      "id": "daily-009-s003",
                      "order": 3,
                      "speaker": "A",
                      "zh": "不是，你打错了。",
                      "pinyin": "Bú shì, nǐ dǎ cuò le.",
                      "vi": "Không phải, bạn gọi nhầm rồi.",
                      "start": 4.862,
                      "end": 7.422
                    },
                    {
                      "id": "daily-009-s004",
                      "order": 4,
                      "speaker": "B",
                      "zh": "不好意思，我打错电话了。",
                      "pinyin": "Bù hǎoyìsi, wǒ dǎ cuò diànhuà le.",
                      "vi": "Xin lỗi, tôi gọi nhầm số rồi.",
                      "start": 7.422,
                      "end": 10.377
                    },
                    {
                      "id": "daily-009-s005",
                      "order": 5,
                      "speaker": "A",
                      "zh": "没关系。你要找谁？",
                      "pinyin": "Méi guānxi. Nǐ yào zhǎo shuí?",
                      "vi": "Không sao. Bạn muốn tìm ai?",
                      "start": 10.377,
                      "end": 12.761
                    },
                    {
                      "id": "daily-009-s006",
                      "order": 6,
                      "speaker": "B",
                      "zh": "我要找李明经理。",
                      "pinyin": "Wǒ yào zhǎo Lǐ Míng jīnglǐ.",
                      "vi": "Tôi muốn tìm quản lý Lý Minh.",
                      "start": 12.761,
                      "end": 14.814
                    },
                    {
                      "id": "daily-009-s007",
                      "order": 7,
                      "speaker": "A",
                      "zh": "你可能少打了一个数字。",
                      "pinyin": "Nǐ kěnéng shǎo dǎ le yí ge shùzì.",
                      "vi": "Có thể bạn bấm thiếu một số.",
                      "start": 14.814,
                      "end": 17.712
                    },
                    {
                      "id": "daily-009-s008",
                      "order": 8,
                      "speaker": "B",
                      "zh": "是吗？我看一下号码。",
                      "pinyin": "Shì ma? Wǒ kàn yí xià hàomǎ.",
                      "vi": "Vậy à? Tôi xem lại số.",
                      "start": 17.712,
                      "end": 20.808
                    },
                    {
                      "id": "daily-009-s009",
                      "order": 9,
                      "speaker": "A",
                      "zh": "你最好再确认一下。",
                      "pinyin": "Nǐ zuì hǎo zài quèrèn yí xià.",
                      "vi": "Tốt nhất bạn xác nhận lại một chút.",
                      "start": 20.808,
                      "end": 24.006
                    },
                    {
                      "id": "daily-009-s010",
                      "order": 10,
                      "speaker": "B",
                      "zh": "好的。真的不好意思，打扰你了。",
                      "pinyin": "Hǎo de. Zhēn de bù hǎoyìsi, dǎrǎo nǐ le.",
                      "vi": "Được. Thật sự xin lỗi, đã làm phiền bạn.",
                      "start": 24.006,
                      "end": 27.412
                    },
                    {
                      "id": "daily-009-s011",
                      "order": 11,
                      "speaker": "A",
                      "zh": "没事。",
                      "pinyin": "Méi shì.",
                      "vi": "Không sao.",
                      "start": 27.412,
                      "end": 28.751
                    },
                    {
                      "id": "daily-009-s012",
                      "order": 12,
                      "speaker": "B",
                      "zh": "谢谢你提醒我。",
                      "pinyin": "Xièxie nǐ tíxǐng wǒ.",
                      "vi": "Cảm ơn bạn đã nhắc tôi.",
                      "start": 28.751,
                      "end": 30.838
                    },
                    {
                      "id": "daily-009-s013",
                      "order": 13,
                      "speaker": "A",
                      "zh": "不客气。",
                      "pinyin": "Bú kèqi.",
                      "vi": "Không có gì.",
                      "start": 30.838,
                      "end": 32.564
                    },
                    {
                      "id": "daily-009-s014",
                      "order": 14,
                      "speaker": "B",
                      "zh": "再见。",
                      "pinyin": "Zàijiàn.",
                      "vi": "Tạm biệt.",
                      "start": 32.564,
                      "end": 33.433
                    }
                  ],
