                  "title_zh": "询问菜的辣度",
                  "title_vi": "Hỏi về độ cay của món ăn",
                  "main_audio_includes_title": false,
                  "title_audio": "audio/catalog/dialogue/beginner/topic-order-milk-tea-and-meals-001/title/daily-003-title.mp3",
                  "main_audio": "audio/catalog/dialogue/beginner/topic-order-milk-tea-and-meals-001/main/daily-003-main.mp3",
                  "speaker": "A/B",
                  "roles": [
                    {
                      "speaker": "A",
                      "name_zh": "服务员",
                      "name_vi": "Phục vụ",
                      "gender": "female",
                      "role_zh": "服务员",
                      "role_vi": "nhân viên phục vụ",
                      "voice_name": "元气主播",
                      "voice_id": "99f8e663",
                      "voice_key": "dialogue_female_daily",
                      "speaker_key": "dialogue_female_daily"
                    },
                    {
                      "speaker": "B",
                      "name_zh": "阿南",
                      "name_vi": "A Nam",
                      "gender": "male",
                      "role_zh": "新员工",
                      "role_vi": "nhân viên mới",
                      "voice_name": "俊杰",
                      "voice_id": "3e2a5eff",
                      "voice_key": "dialogue_male_daily",
                      "speaker_key": "dialogue_male_daily"
                    }
                  ],
                  "sentences": [
                    {
                      "id": "daily-003-s001",
                      "order": 1,
                      "speaker": "A",
                      "zh": "你好，几位？",
                      "pinyin": "Nǐ hǎo, jǐ wèi?",
                      "vi": "Xin chào, mấy người ạ?",
                      "start": 0,
                      "end": 1.92
                    },
                    {
                      "id": "daily-003-s002",
                      "order": 2,
                      "speaker": "B",
                      "zh": "两位。",
                      "pinyin": "Liǎng wèi.",
                      "vi": "Hai người.",
                      "start": 1.92,
                      "end": 2.95
                    },
                    {
                      "id": "daily-003-s003",
                      "order": 3,
                      "speaker": "A",
                      "zh": "这边请。你们想吃点什么？",
                      "pinyin": "Zhè biān qǐng. Nǐmen xiǎng chī diǎn shénme?",
                      "vi": "Mời bên này. Hai bạn muốn ăn gì?",
                      "start": 2.95,
                      "end": 6.811
                    },
                    {
                      "id": "daily-003-s004",
                      "order": 4,
                      "speaker": "B",
                      "zh": "我们先看一下菜单。",
                      "pinyin": "Wǒmen xiān kàn yí xià càidān.",
                      "vi": "Chúng tôi xem thực đơn trước.",
                      "start": 6.811,
                      "end": 9.198
                    },
                    {
                      "id": "daily-003-s005",
                      "order": 5,
                      "speaker": "A",
                      "zh": "好的。这个是我们店的招牌菜。",
                      "pinyin": "Hǎo de. Zhè ge shì wǒmen diàn de zhāopái cài.",
                      "vi": "Được. Đây là món đặc trưng của quán chúng tôi.",
                      "start": 9.198,
                      "end": 12.535
                    },
                    {
                      "id": "daily-003-s006",
                      "order": 6,
                      "speaker": "B",
                      "zh": "这个菜辣不辣？",
                      "pinyin": "Zhè ge cài là bu là?",
                      "vi": "Món này có cay không?",
                      "start": 12.535,
                      "end": 14.611
                    },
                    {
                      "id": "daily-003-s007",
                      "order": 7,
                      "speaker": "A",
                      "zh": "有一点儿辣，但是不太辣。",
                      "pinyin": "Yǒu yìdiǎnr là, dànshì bú tài là.",
                      "vi": "Hơi cay, nhưng không quá cay.",
                      "start": 14.611,
                      "end": 17.303
                    },
                    {
                      "id": "daily-003-s008",
                      "order": 8,
                      "speaker": "B",
                      "zh": "我不太能吃辣。",
                      "pinyin": "Wǒ bú tài néng chī là.",
                      "vi": "Tôi không ăn cay giỏi lắm.",
                      "start": 17.303,
                      "end": 19.468
                    },
                    {
                      "id": "daily-003-s009",
                      "order": 9,
                      "speaker": "A",
                      "zh": "那你可以点这个鸡蛋炒饭。",
                      "pinyin": "Nà nǐ kě yǐ diǎn zhè ge jīdàn chǎofàn.",
                      "vi": "Vậy bạn có thể gọi cơm chiên trứng này.",
                      "start": 19.468,
                      "end": 22.161
                    },
                    {
                      "id": "daily-003-s010",
                      "order": 10,
                      "speaker": "B",
                      "zh": "这个不辣吗？",
                      "pinyin": "Zhè ge bú là ma?",
                      "vi": "Món này không cay à?",
                      "start": 22.161,
                      "end": 24.198
                    },
                    {
                      "id": "daily-003-s011",
                      "order": 11,
                      "speaker": "A",
                      "zh": "对，不辣，很多外国客人都喜欢。",
                      "pinyin": "Duì, bú là, hěn duō wàiguó kèrén dōu xǐhuan.",
                      "vi": "Đúng, không cay, nhiều khách nước ngoài đều thích.",
                      "start": 24.198,
                      "end": 28.399
                    },
                    {
                      "id": "daily-003-s012",
                      "order": 12,
                      "speaker": "B",
                      "zh": "好，那我要一份鸡蛋炒饭。",
                      "pinyin": "Hǎo, nà wǒ yào yí fèn jīdàn chǎofàn.",
                      "vi": "Được, vậy tôi lấy một phần cơm chiên trứng.",
                      "start": 28.399,
                      "end": 31.044
                    },
                    {
                      "id": "daily-003-s013",
                      "order": 13,
                      "speaker": "A",
                      "zh": "还要喝的吗？",
                      "pinyin": "Hái yào hē de ma?",
                      "vi": "Còn muốn đồ uống không?",
                      "start": 31.044,
                      "end": 32.744
                    },
                    {
                      "id": "daily-003-s014",
                      "order": 14,
                      "speaker": "B",
                      "zh": "要一杯水。",
                      "pinyin": "Yào yì bēi shuǐ.",
                      "vi": "Lấy một ly nước.",
                      "start": 32.744,
                      "end": 34.623
                    },
                    {
                      "id": "daily-003-s015",
                      "order": 15,
                      "speaker": "A",
                      "zh": "好的，请稍等。",
                      "pinyin": "Hǎo de, qǐng shāo děng.",
                      "vi": "Được, vui lòng đợi một lát.",
                      "start": 34.623,
                      "end": 36.632
                    },
                    {
                      "id": "daily-003-s016",
                      "order": 16,
                      "speaker": "B",
                      "zh": "谢谢。",
                      "pinyin": "Xièxie.",
                      "vi": "Cảm ơn.",
                      "start": 36.632,
                      "end": 37.66
                    }
                  ],
