                  "sentences": [
                    {
                      "id": "daily-004-s001",
                      "order": 1,
                      "speaker": "A",
                      "zh": "李娜，你中午有时间吗？",
                      "pinyin": "Lǐ Nà, nǐ zhōngwǔ yǒu shíjiān ma?",
                      "vi": "Lý Na, trưa nay bạn có thời gian không?",
                      "start": 0,
                      "end": 2.63
                    },
                    {
                      "id": "daily-004-s002",
                      "order": 2,
                      "speaker": "B",
                      "zh": "有啊，怎么了？",
                      "pinyin": "Yǒu a, zěnme le?",
                      "vi": "Có chứ, sao vậy?",
                      "start": 2.63,
                      "end": 4.857
                    },
                    {
                      "id": "daily-004-s003",
                      "order": 3,
                      "speaker": "A",
                      "zh": "我想请你一起吃饭。",
                      "pinyin": "Wǒ xiǎng qǐng nǐ yìqǐ chīfàn.",
                      "vi": "Tôi muốn mời bạn đi ăn cùng.",
                      "start": 4.857,
                      "end": 7.486
                    },
                    {
                      "id": "daily-004-s004",
                      "order": 4,
                      "speaker": "B",
                      "zh": "好啊。你想吃什么？",
                      "pinyin": "Hǎo a. Nǐ xiǎng chī shénme?",
                      "vi": "Được chứ. Bạn muốn ăn gì?",
                      "start": 7.486,
                      "end": 10.232
                    },
                    {
                      "id": "daily-004-s005",
                      "order": 5,
                      "speaker": "A",
                      "zh": "我想吃中国菜，但是我不知道哪家好吃。",
                      "pinyin": "Wǒ xiǎng chī Zhōngguó cài, dànshì wǒ bù zhīdào nǎ jiā hǎochī.",
                      "vi": "Tôi muốn ăn món Trung Quốc, nhưng không biết quán nào ngon.",
                      "start": 10.232,
                      "end": 14.101
                    },
                    {
                      "id": "daily-004-s006",
                      "order": 6,
                      "speaker": "B",
                      "zh": "附近有一家面馆不错。",
                      "pinyin": "Fùjìn yǒu yì jiā miànguǎn bú cuò.",
                      "vi": "Gần đây có một quán mì khá ổn.",
                      "start": 14.101,
                      "end": 16.95
                    },
                    {
                      "id": "daily-004-s007",
                      "order": 7,
                      "speaker": "A",
                      "zh": "远吗？",
                      "pinyin": "Yuǎn ma?",
                      "vi": "Có xa không?",
                      "start": 16.95,
                      "end": 18.287
                    },
                    {
                      "id": "daily-004-s008",
                      "order": 8,
                      "speaker": "B",
                      "zh": "不远，走路十分钟就到。",
                      "pinyin": "Bù yuǎn, zǒulù shí fēnzhōng jiù dào.",
                      "vi": "Không xa, đi bộ 10 phút là tới.",
                      "start": 18.287,
                      "end": 20.386
                    },
                    {
                      "id": "daily-004-s009",
                      "order": 9,
                      "speaker": "A",
                      "zh": "太好了。那我们几点去？",
                      "pinyin": "Tài hǎo le. Nà wǒmen jǐ diǎn qù?",
                      "vi": "Tốt quá. Vậy mấy giờ chúng ta đi?",
                      "start": 20.386,
                      "end": 23.389
                    },
                    {
                      "id": "daily-004-s010",
                      "order": 10,
                      "speaker": "B",
                      "zh": "十二点可以吗？",
                      "pinyin": "Shí'èr diǎn kě yǐ ma?",
                      "vi": "12 giờ được không?",
                      "start": 23.389,
                      "end": 25.425
                    },
                    {
                      "id": "daily-004-s011",
                      "order": 11,
                      "speaker": "A",
                      "zh": "可以。我在公司门口等你。",
                      "pinyin": "Kě yǐ. Wǒ zài gōngsī ménkǒu děng nǐ.",
                      "vi": "Được. Tôi đợi bạn ở cổng công ty.",
                      "start": 25.425,
                      "end": 28.477
                    },
                    {
                      "id": "daily-004-s012",
                      "order": 12,
                      "speaker": "B",
                      "zh": "好。你喜欢吃辣吗？",
                      "pinyin": "Hǎo. Nǐ xǐhuan chī là ma?",
                      "vi": "Được. Bạn thích ăn cay không?",
                      "start": 28.477,
                      "end": 31.313
                    },
                    {
                      "id": "daily-004-s013",
                      "order": 13,
                      "speaker": "A",
                      "zh": "不太喜欢。我怕太辣。",
                      "pinyin": "Bú tài xǐhuan. Wǒ pà tài là.",
                      "vi": "Không thích lắm. Tôi sợ quá cay.",
                      "start": 31.313,
                      "end": 34.195
                    },
                    {
                      "id": "daily-004-s014",
                      "order": 14,
                      "speaker": "B",
                      "zh": "没问题。我们可以点不辣的菜。",
                      "pinyin": "Méi wèntí. Wǒmen kě yǐ diǎn bú là de cài.",
                      "vi": "Không vấn đề. Chúng ta có thể gọi món không cay.",
                      "start": 34.195,
                      "end": 37.249
                    },
                    {
                      "id": "daily-004-s015",
                      "order": 15,
                      "speaker": "A",
                      "zh": "好，谢谢你。",
                      "pinyin": "Hǎo, xièxie nǐ.",
                      "vi": "Được, cảm ơn bạn.",
                      "start": 37.249,
                      "end": 39.414
                    },
                    {
                      "id": "daily-004-s016",
                      "order": 16,
                      "speaker": "B",
                      "zh": "不客气，一会儿见。",
                      "pinyin": "Bú kèqi, yíhuìr jiàn.",
                      "vi": "Không có gì, lát gặp nhé.",
                      "start": 39.414,
                      "end": 41.757
                    }
                  ],
