                  "title_vi": "Không biết nên gọi món gì",
                  "main_audio_includes_title": false,
                  "title_audio": "audio/catalog/dialogue/beginner/topic-order-milk-tea-and-meals-001/title/daily-005-title.mp3",
                  "main_audio": "audio/catalog/dialogue/beginner/topic-order-milk-tea-and-meals-001/main/daily-005-main.mp3",
                  "speaker": "A/B",
                  "roles": [
                    {
                      "speaker": "A",
                      "name_zh": "服务员",
                      "name_vi": "Phục vụ",
                      "gender": "male",
                      "role_zh": "服务员",
                      "role_vi": "nhân viên phục vụ",
                      "voice_name": "俊杰",
                      "voice_id": "3e2a5eff",
                      "voice_key": "dialogue_male_daily",
                      "speaker_key": "dialogue_male_daily"
                    },
                    {
                      "speaker": "B",
                      "name_zh": "小玲",
                      "name_vi": "Tiểu Linh",
                      "gender": "female",
                      "role_zh": "同事",
                      "role_vi": "đồng nghiệp",
                      "voice_name": "元气主播",
                      "voice_id": "99f8e663",
                      "voice_key": "dialogue_female_daily",
                      "speaker_key": "dialogue_female_daily"
                    }
                  ],
                  "sentences": [
                    {
                      "id": "daily-005-s001",
                      "order": 1,
                      "speaker": "A",
                      "zh": "你好，请问现在点菜吗？",
                      "pinyin": "Nǐ hǎo, qǐngwèn xiànzài diǎn cài ma?",
                      "vi": "Xin chào, bây giờ gọi món chưa ạ?",
                      "start": 0,
                      "end": 3.467
                    },
                    {
                      "id": "daily-005-s002",
                      "order": 2,
                      "speaker": "B",
                      "zh": "我还不知道点什么。",
                      "pinyin": "Wǒ hái bù zhīdào diǎn shénme.",
                      "vi": "Tôi vẫn chưa biết gọi món gì.",
                      "start": 3.467,
                      "end": 6.323
                    },
                    {
                      "id": "daily-005-s003",
                      "order": 3,
                      "speaker": "A",
                      "zh": "你喜欢吃米饭还是面条？",
                      "pinyin": "Nǐ xǐhuan chī mǐfàn háishi miàntiáo?",
                      "vi": "Bạn thích ăn cơm hay mì?",
                      "start": 6.323,
                      "end": 9.225
                    },
                    {
                      "id": "daily-005-s004",
                      "order": 4,
                      "speaker": "B",
                      "zh": "我喜欢吃米饭。",
                      "pinyin": "Wǒ xǐhuan chī mǐfàn.",
                      "vi": "Tôi thích ăn cơm.",
                      "start": 9.225,
                      "end": 11.517
                    },
                    {
                      "id": "daily-005-s005",
                      "order": 5,
                      "speaker": "A",
                      "zh": "那可以点鸡肉饭，很多客人都喜欢。",
                      "pinyin": "Nà kě yǐ diǎn jīròu fàn, hěn duō kèrén dōu xǐhuan.",
                      "vi": "Vậy có thể gọi cơm gà, nhiều khách đều thích.",
                      "start": 11.517,
                      "end": 14.858
                    },
                    {
                      "id": "daily-005-s006",
                      "order": 6,
                      "speaker": "B",
                      "zh": "这个饭辣吗？",
                      "pinyin": "Zhè ge fàn là ma?",
                      "vi": "Cơm này có cay không?",
                      "start": 14.858,
                      "end": 17.371
                    },
                    {
                      "id": "daily-005-s007",
                      "order": 7,
                      "speaker": "A",
                      "zh": "不辣。味道比较清淡。",
                      "pinyin": "Bú là. Wèidào bǐjiào qīngdàn.",
                      "vi": "Không cay. Vị tương đối thanh đạm.",
                      "start": 17.371,
                      "end": 20.025
                    },
                    {
                      "id": "daily-005-s008",
                      "order": 8,
                      "speaker": "B",
                      "zh": "好，那我要一份鸡肉饭。",
                      "pinyin": "Hǎo, nà wǒ yào yí fèn jīròu fàn.",
                      "vi": "Được, vậy tôi lấy một phần cơm gà.",
                      "start": 20.025,
                      "end": 22.589
                    },
                    {
                      "id": "daily-005-s009",
                      "order": 9,
                      "speaker": "A",
                      "zh": "还要一个汤吗？",
                      "pinyin": "Hái yào yí ge tāng ma?",
                      "vi": "Có muốn thêm một bát canh không?",
                      "start": 22.589,
                      "end": 24.415
                    },
                    {
                      "id": "daily-005-s010",
                      "order": 10,
                      "speaker": "B",
                      "zh": "什么汤？",
                      "pinyin": "Shénme tāng?",
                      "vi": "Canh gì?",
                      "start": 24.415,
                      "end": 25.907
                    },
                    {
                      "id": "daily-005-s011",
                      "order": 11,
                      "speaker": "A",
                      "zh": "西红柿鸡蛋汤。",
                      "pinyin": "Xīhóngshì jīdàn tāng.",
                      "vi": "Canh cà chua trứng.",
                      "start": 25.907,
                      "end": 28.224
                    },
                    {
                      "id": "daily-005-s012",
                      "order": 12,
                      "speaker": "B",
                      "zh": "听起来不错。来一碗吧。",
                      "pinyin": "Tīng qǐlai bú cuò. Lái yì wǎn ba.",
                      "vi": "Nghe có vẻ được. Cho tôi một bát nhé.",
                      "start": 28.224,
                      "end": 31.849
                    },
                    {
                      "id": "daily-005-s013",
                      "order": 13,
                      "speaker": "A",
                      "zh": "好的。喝的要什么？",
                      "pinyin": "Hǎo de. Hē de yào shénme?",
                      "vi": "Được. Đồ uống muốn gì?",
                      "start": 31.849,
                      "end": 34.438
                    },
                    {
                      "id": "daily-005-s014",
                      "order": 14,
                      "speaker": "B",
                      "zh": "给我一杯热茶。",
                      "pinyin": "Gěi wǒ yì bēi rè chá.",
                      "vi": "Cho tôi một ly trà nóng.",
                      "start": 34.438,
                      "end": 36.563
                    },
                    {
                      "id": "daily-005-s015",
                      "order": 15,
                      "speaker": "A",
                      "zh": "好的，请稍等。",
                      "pinyin": "Hǎo de, qǐng shāo děng.",
                      "vi": "Được, vui lòng đợi một lát.",
                      "start": 36.563,
                      "end": 38.795
                    },
                    {
                      "id": "daily-005-s016",
                      "order": 16,
                      "speaker": "B",
                      "zh": "谢谢。",
                      "pinyin": "Xièxie.",
                      "vi": "Cảm ơn.",
                      "start": 38.795,
                      "end": 40.184
                    }
                  ],
