                  "zh": "觉察",
                  "pinyin": "juéchá",
                  "vi": "nhận biết, tự quan sát",
                  "audio": "audio/catalog/monologue/other/topic-emotional-essay-other-001/words/daily-003-keyword-007.mp3"
